250	impl std::fmt::Display for AssemblyError {
251	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
252	        write!(f, "line {}: {}", self.line, self.message)
253	    }
254	}
255	
256	/// A loaded .p24 binary image.
257	pub struct LoadedImage {
258	    pub entry_point: u32,
259	    pub code: Vec<u8>,
260	    pub data: Vec<u8>,
261	    pub global_count: u32,
262	}
263	
264	/// Error loading a .p24 binary.
265	#[derive(Debug)]
266	pub enum LoadError {
267	    TooShort,
268	    BadMagic,
269	    BadVersion(u8),
270	    Truncated,
271	}
272	
273	impl std::fmt::Display for LoadError {
274	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
275	        match self {
276	            LoadError::TooShort => write!(f, "file too short for .p24 header"),
277	            LoadError::BadMagic => write!(f, "invalid .p24 magic bytes"),
278	            LoadError::BadVersion(v) => write!(f, "unsupported .p24 version: {v}"),
279	            LoadError::Truncated => write!(f, "file truncated: body shorter than header declares"),
280	        }
281	    }
282	}
