284	use std::collections::HashMap;
285	
286	use lexer::{Token, tokenize};
287	
288	/// Metadata directives from pl24r that we silently skip.
289	const METADATA_DIRECTIVES: &[&str] = &[".module", ".export", ".extern", ".endmodule"];
290	
291	/// Symbol type for tracking what kind of entity a name refers to.
292	#[derive(Debug, Clone, Copy)]
293	enum SymType {
294	    Code,
295	    Data,
296	    Global,
297	    Const,
298	}
299	
300	/// A symbol table entry.
301	#[derive(Debug, Clone)]
302	struct Symbol {
303	    value: u32,
304	    sym_type: SymType,
305	    line: usize,
306	}
307	
308	/// Assemble .spc source into separate code and data segments.
309	pub fn assemble(source: &str) -> AssemblyResult {
310	    let tokens = tokenize(source);
311	    let mut symbols: HashMap<String, Symbol> = HashMap::new();
312	    let mut errors: Vec<AssemblyError> = Vec::new();
313	    let mut data_bytes: Vec<u8> = Vec::new();
314	    let mut code_offset: u32 = 0;
315	    let mut data_offset: u32 = 0;
316	    let mut global_offset: u32 = 0;
317	    let mut entry_point: Option<u32> = None;
318	
319	    // ── Pass 1: Symbol Collection ──
320	
321	    let mut i = 0;
322	    while i < tokens.len() {
323	        let tok = &tokens[i];
324	        match &tok.token {
325	            Token::Newline => {
326	                i += 1;
327	            }
328	
329	            Token::Label(name) => {
330	                if let Err(e) =
331	                    insert_symbol(&mut symbols, name, code_offset, SymType::Code, tok.line)
332	                {
333	                    errors.push(e);
334	                }
335	                i += 1;
336	            }
337	
338	            Token::Directive(dir) => {
339	                let line = tok.line;
340	                i += 1;
341	                match dir.as_str() {
342	                    ".proc" => {
343	                        // .proc <name> <nargs>
344	                        // Auto-emit `enter N` as first instruction (matches pasm.s)
345	                        let name = expect_identifier(&tokens, &mut i);
346	                        if let Some(name) = name {
347	                            if name == "main" {
348	                                entry_point = Some(code_offset);
349	                            }
350	                            if let Err(e) =
351	                                insert_symbol(&mut symbols, &name, code_offset, SymType::Code, line)
352	                            {
353	                                errors.push(e);
354	                            }
355	                        } else {
356	                            errors.push(AssemblyError {
357	                                line,
358	                                message: ".proc missing name".into(),
359	                            });
360	                        }
361	                        // Read nargs for the auto-emitted enter instruction
362	                        let _nargs = expect_number(&tokens, &mut i).unwrap_or(0);
363	                        code_offset += Opcode::Enter.size() as u32; // enter N = 2 bytes
364	                        skip_to_newline(&tokens, &mut i);
365	                    }
366	                    ".end" => {
367	                        // Auto-emit `leave` before implicit end (matches pasm.s)
368	                        code_offset += Opcode::Leave.size() as u32; // leave = 1 byte
369	                        skip_to_newline(&tokens, &mut i);
370	                    }
371	                    ".data" => {
372	                        // .data <name> <byte>, <byte>, ...
373	                        let name = expect_identifier(&tokens, &mut i);
374	                        if let Some(name) = name {
375	                            if let Err(e) =
376	                                insert_symbol(&mut symbols, &name, data_offset, SymType::Data, line)
377	                            {
378	                                errors.push(e);
379	                            }
380	                        } else {
381	                            errors.push(AssemblyError {
382	                                line,
383	                                message: ".data missing name".into(),
384	                            });
385	                        }
386	                        // Collect bytes
387	                        while i < tokens.len() && tokens[i].token != Token::Newline {
388	                            match &tokens[i].token {
389	                                Token::Number(n) => {
390	                                    data_bytes.push(*n as u8);
391	                                    data_offset += 1;
392	                                    i += 1;
393	                                }
394	                                Token::Comma => {
395	                                    i += 1;
396	                                }
397	                                _ => {
398	                                    i += 1;
399	                                }
400	                            }
401	                        }
402	                    }
403	                    ".global" => {
404	                        // .global <name> <count>
405	                        let name = expect_identifier(&tokens, &mut i);
406	                        let count = expect_number(&tokens, &mut i).unwrap_or(1);
407	                        if let Some(name) = name {
408	                            if let Err(e) = insert_symbol(
409	                                &mut symbols,
410	                                &name,
411	                                global_offset,
412	                                SymType::Global,
413	                                line,
414	                            ) {
415	                                errors.push(e);
416	                            }
417	                        } else {
418	                            errors.push(AssemblyError {
419	                                line,
420	                                message: ".global missing name".into(),
421	                            });
422	                        }
423	                        global_offset += count as u32 * 3;
424	                        skip_to_newline(&tokens, &mut i);
425	                    }
426	                    ".const" => {
427	                        // .const <name> <value>
428	                        let name = expect_identifier(&tokens, &mut i);
429	                        let value = expect_number(&tokens, &mut i).unwrap_or(0);
430	                        if let Some(name) = name {
431	                            if let Err(e) = insert_symbol(
432	                                &mut symbols,
433	                                &name,
434	                                value as u32,
435	                                SymType::Const,
436	                                line,
437	                            ) {
438	                                errors.push(e);
439	                            }
440	                        } else {
441	                            errors.push(AssemblyError {
442	                                line,
443	                                message: ".const missing name".into(),
444	                            });
445	                        }
446	                        skip_to_newline(&tokens, &mut i);
447	                    }
448	                    d if METADATA_DIRECTIVES.contains(&d) => {
449	                        skip_to_newline(&tokens, &mut i);
450	                    }
451	                    _ => {
452	                        // Unknown directive — skip silently (may be from pl24r)
453	                        skip_to_newline(&tokens, &mut i);
454	                    }
455	                }
456	            }
457	
458	            Token::Identifier(name) => {
459	                // Instruction mnemonic
460	                let line = tok.line;
461	                if let Some(op) = Opcode::from_mnemonic(name) {
462	                    code_offset += op.size() as u32;
463	                    i += 1;
464	                    // Skip any operand tokens on this line
465	                    skip_to_newline(&tokens, &mut i);
466	                } else {
467	                    errors.push(AssemblyError {
468	                        line,
469	                        message: format!("unknown mnemonic: {name}"),
470	                    });
471	                    i += 1;
472	                    skip_to_newline(&tokens, &mut i);
473	                }
474	            }
475	
476	            _ => {
477	                i += 1;
478	            }
479	        }
480	    }
481	
482	    let code_size = code_offset;
483	    let data_size = data_offset;
484	    let global_count = global_offset / 3;
485	
486	    // Patch data symbols: add code_size (data follows code in memory)
487	    // Global symbols are NOT patched here — their value stays as the raw
488	    // word index. The code emitter adjusts based on context: loadg/storeg
489	    // use the raw word index, while push uses code_size + data_size + index.
490	    for sym in symbols.values_mut() {
491	        if let SymType::Data = sym.sym_type {
492	            sym.value += code_size;
493	        }
494	    }
495	
496	    if entry_point.is_none() {
497	        errors.push(AssemblyError {
498	            line: 0,
499	            message: "missing .proc main".into(),
500	        });
501	    }
502	
503	    // ── Pass 2: Code Emission ──
504	
505	    let global_base = code_size + data_size;
506	    let mut code: Vec<u8> = Vec::with_capacity(code_size as usize);
507	    i = 0;
508	    while i < tokens.len() {
509	        let tok = &tokens[i];
510	        match &tok.token {
511	            Token::Newline | Token::Label(_) | Token::Comma => {
512	                i += 1;
513	            }
514	
515	            Token::Directive(dir) => {
516	                i += 1;
517	                match dir.as_str() {
518	                    ".proc" => {
519	                        // Auto-emit enter N
520	                        let _name = expect_identifier(&tokens, &mut i);
521	                        let nargs = expect_number(&tokens, &mut i).unwrap_or(0);
522	                        code.push(Opcode::Enter as u8);
523	                        code.push(nargs as u8);
524	                        skip_to_newline(&tokens, &mut i);
525	                    }
526	                    ".end" => {
527	                        // Auto-emit leave
528	                        code.push(Opcode::Leave as u8);
529	                        skip_to_newline(&tokens, &mut i);
530	                    }
531	                    _ => {
532	                        skip_to_newline(&tokens, &mut i);
533	                    }
534	                }
535	            }
536	
537	            Token::Identifier(name) => {
538	                let line = tok.line;
539	                if let Some(op) = Opcode::from_mnemonic(name) {
540	                    code.push(op as u8);
541	                    i += 1;
542	
543	                    match op.encoding() {
544	                        Encoding::None => {
545	                            // Ignore trailing operand (e.g. `ret 1`)
546	                            skip_to_newline(&tokens, &mut i);
547	                        }
548	                        Encoding::Imm8 => {
549	                            let val = resolve_operand(
550	                                &tokens,
551	                                &mut i,
552	                                &symbols,
553	                                line,
554	                                &mut errors,
555	                                Some(global_base),
556	                            );
557	                            code.push(val as u8);
558	                            skip_to_newline(&tokens, &mut i);
559	                        }
560	                        Encoding::Imm24 => {
561	                            // loadg/storeg/addrg use raw word index for globals
562	                            let gb = match op {
563	                                Opcode::Loadg | Opcode::Storeg | Opcode::Addrg => None,
564	                                _ => Some(global_base),
565	                            };
566	                            let val =
567	                                resolve_operand(&tokens, &mut i, &symbols, line, &mut errors, gb);
568	                            emit_le24(&mut code, val);
569	                            skip_to_newline(&tokens, &mut i);
570	                        }
571	                        Encoding::D8A24 => {
572	                            // d8, a24 — two operands (depth, address)
573	                            let d = resolve_operand(
574	                                &tokens,
575	                                &mut i,
576	                                &symbols,
577	                                line,
578	                                &mut errors,
579	                                Some(global_base),
580	                            );
581	                            // skip comma if present
582	                            if i < tokens.len() && tokens[i].token == Token::Comma {
583	                                i += 1;
584	                            }
585	                            let a = resolve_operand(
586	                                &tokens,
587	                                &mut i,
588	                                &symbols,
589	                                line,
590	                                &mut errors,
591	                                Some(global_base),
592	                            );
593	                            code.push(d as u8);
594	                            emit_le24(&mut code, a);
595	                            skip_to_newline(&tokens, &mut i);
596	                        }
597	                        Encoding::D8O8 => {
598	                            // d8, o8 — two operands
599	                            let d = resolve_operand(
600	                                &tokens,
601	                                &mut i,
602	                                &symbols,
603	                                line,
604	                                &mut errors,
605	                                Some(global_base),
606	                            );
607	                            if i < tokens.len() && tokens[i].token == Token::Comma {
608	                                i += 1;
609	                            }
610	                            let o = resolve_operand(
611	                                &tokens,
612	                                &mut i,
613	                                &symbols,
614	                                line,
615	                                &mut errors,
616	                                Some(global_base),
617	                            );
618	                            code.push(d as u8);
619	                            code.push(o as u8);
620	                            skip_to_newline(&tokens, &mut i);
621	                        }
622	                    }
623	                } else {
624	                    // Unknown mnemonic — already reported in pass 1
625	                    i += 1;
626	                    skip_to_newline(&tokens, &mut i);
627	                }
628	            }
629	
630	            _ => {
631	                i += 1;
632	            }
633	        }
634	    }
635	
636	    AssemblyResult {
637	        code,
638	        data: data_bytes,
639	        entry_point: entry_point.unwrap_or(0),
640	        global_count,
641	        errors,
642	    }
643	}
644	
645	/// Assemble .spc source and produce a complete .p24 binary.
646	pub fn assemble_to_p24(source: &str) -> Result<Vec<u8>, Vec<AssemblyError>> {
647	    let result = assemble(source);
648	    if !result.errors.is_empty() {
649	        return Err(result.errors);
650	    }
651	
652	    let mut binary = Vec::with_capacity(P24_HEADER_SIZE + result.code.len() + result.data.len());
653	
654	    // Header
655	    binary.extend_from_slice(&P24_MAGIC);
656	    binary.push(P24_VERSION);
657	    emit_le24(&mut binary, result.entry_point);
658	    emit_le24(&mut binary, result.code.len() as u32);
659	    emit_le24(&mut binary, result.data.len() as u32);
660	    emit_le24(&mut binary, result.global_count);
661	    binary.push(0x00); // flags
662	
663	    // Body
664	    binary.extend_from_slice(&result.code);
665	    binary.extend_from_slice(&result.data);
666	
667	    Ok(binary)
668	}
669	
670	/// Load a .p24 binary into a LoadedImage.
671	pub fn load_p24(binary: &[u8]) -> Result<LoadedImage, LoadError> {
672	    if binary.len() < P24_HEADER_SIZE {
673	        return Err(LoadError::TooShort);
674	    }
675	    if binary[0..4] != P24_MAGIC {
676	        return Err(LoadError::BadMagic);
677	    }
678	    let version = binary[4];
679	    if version != P24_VERSION {
680	        return Err(LoadError::BadVersion(version));
681	    }
682	
683	    let entry_point = read_le24(&binary[5..8]);
684	    let code_size = read_le24(&binary[8..11]) as usize;
685	    let data_size = read_le24(&binary[11..14]) as usize;
686	    let global_count = read_le24(&binary[14..17]);
687	
688	    let body = &binary[P24_HEADER_SIZE..];
689	    if body.len() < code_size + data_size {
690	        return Err(LoadError::Truncated);
691	    }
692	
693	    Ok(LoadedImage {
694	        entry_point,
695	        code: body[..code_size].to_vec(),
696	        data: body[code_size..code_size + data_size].to_vec(),
697	        global_count,
698	    })
699	}
700	
701	/// Relocate push instructions that reference the data or global segments.
702	///
703	/// After assembly, `push` operands that reference data are encoded as
704	/// offsets from the start of the combined code+data buffer (values at
705	/// or above `code_size`). When loading into emulator memory at a specific
706	/// address, these operands need `load_addr` added to become absolute.
707	///
708	/// Walks the code bytes, finds each instruction by opcode and encoding,
709	/// and adjusts any `push` (IMM24) operand that falls at or above `code_size`.
710	pub fn relocate_data_refs(code: &mut [u8], code_size: u32, data_size: u32, load_addr: u32) {
711	    let threshold = code_size;
712	    let limit = code_size + data_size;
713	    let mut pc = 0usize;
714	    while pc < code.len() {
715	        let op_byte = code[pc];
716	        // Try to determine instruction size from opcode encoding.
717	        // We only care about push (0x01) which is IMM24.
718	        let size = if op_byte == Opcode::Push as u8 {
719	            // IMM24: read the 3-byte operand
720	            let val = read_le24(&code[pc + 1..pc + 4]);
721	            if val >= threshold && val < limit {
722	                let relocated = val + load_addr;
723	                code[pc + 1] = relocated as u8;
724	                code[pc + 2] = (relocated >> 8) as u8;
725	                code[pc + 3] = (relocated >> 16) as u8;
726	            }
727	            4
728	        } else {
729	            opcode_size(op_byte)
730	        };
731	        pc += size;
732	    }
733	}
734	
735	/// Get instruction size from raw opcode byte, without requiring a valid Opcode enum value.
736	fn opcode_size(op: u8) -> usize {
737	    // Map opcode byte to encoding size using the same logic as Opcode::encoding().
738	    // This handles unknown opcodes gracefully (treats as 1 byte).
739	    match op {
740	        // IMM8 (2 bytes): push_s, ret, trap, enter, loadl, storel, addrl, loada, storea, sys
741	        0x02 | 0x34 | 0x36 | 0x40 | 0x42 | 0x43 | 0x46 | 0x48 | 0x49 | 0x60 => 2,
742	        // IMM24 (4 bytes): push, jmp, jz, jnz, call, loadg, storeg, addrg
743	        0x01 | 0x30 | 0x31 | 0x32 | 0x33 | 0x44 | 0x45 | 0x47 => 4,
744	        // D8_A24 (5 bytes): calln
745	        0x35 => 5,
746	        // D8_O8 (3 bytes): loadn, storen
747	        0x4A | 0x4B => 3,
748	        // NONE and everything else (1 byte)
749	        _ => 1,
750	    }
751	}
752	
753	// ── Helper functions ──
754	
755	fn insert_symbol(
756	    symbols: &mut HashMap<String, Symbol>,
757	    name: &str,
758	    value: u32,
759	    sym_type: SymType,
760	    line: usize,
761	) -> Result<(), AssemblyError> {
762	    if let Some(existing) = symbols.get(name) {
763	        return Err(AssemblyError {
764	            line,
765	            message: format!(
766	                "duplicate symbol '{name}' (first defined at line {})",
767	                existing.line
768	            ),
769	        });
770	    }
771	    symbols.insert(
772	        name.to_string(),
773	        Symbol {
774	            value,
775	            sym_type,
776	            line,
777	        },
778	    );
779	    Ok(())
780	}
781	
782	fn expect_identifier(tokens: &[lexer::Located], i: &mut usize) -> Option<String> {
783	    if *i < tokens.len()
784	        && let Token::Identifier(name) = &tokens[*i].token
785	    {
786	        let name = name.clone();
787	        *i += 1;
788	        return Some(name);
789	    }
790	    None
791	}
792	
793	fn expect_number(tokens: &[lexer::Located], i: &mut usize) -> Option<i32> {
794	    if *i < tokens.len()
795	        && let Token::Number(n) = &tokens[*i].token
796	    {
797	        let n = *n;
798	        *i += 1;
799	        return Some(n);
800	    }
801	    None
802	}
803	
804	fn skip_to_newline(tokens: &[lexer::Located], i: &mut usize) {
805	    while *i < tokens.len() && tokens[*i].token != Token::Newline {
806	        *i += 1;
807	    }
808	}
809	
810	/// Resolve an operand token to a numeric value.
811	/// `global_base`: if Some, global symbols get this base added (for `push` etc).
812	/// If None, global symbols use raw word index (for `loadg`/`storeg`/`addrg`).
813	fn resolve_operand(
814	    tokens: &[lexer::Located],
815	    i: &mut usize,
816	    symbols: &HashMap<String, Symbol>,
817	    line: usize,
818	    errors: &mut Vec<AssemblyError>,
819	    global_base: Option<u32>,
820	) -> u32 {
821	    if *i >= tokens.len() || tokens[*i].token == Token::Newline {
822	        errors.push(AssemblyError {
823	            line,
824	            message: "missing operand".into(),
825	        });
826	        return 0;
827	    }
828	    match &tokens[*i].token {
829	        Token::Number(n) => {
830	            let val = *n;
831	            *i += 1;
832	            val as u32
833	        }
834	        Token::Identifier(name) => {
835	            *i += 1;
836	            if let Some(sym) = symbols.get(name.as_str()) {
837	                match sym.sym_type {
838	                    SymType::Global => {
839	                        if let Some(base) = global_base {
840	                            // Absolute address: base + word_index * 3
841	                            base + sym.value
842	                        } else {
843	                            // Raw word index for loadg/storeg/addrg
844	                            sym.value / 3
845	                        }
846	                    }
847	                    _ => sym.value,
848	                }
849	            } else {
850	                errors.push(AssemblyError {
851	                    line,
852	                    message: format!("unresolved symbol: {name}"),
853	                });
854	                0
855	            }
856	        }
857	        _ => {
858	            errors.push(AssemblyError {
859	                line,
860	                message: format!("unexpected token as operand: {:?}", tokens[*i].token),
861	            });
862	            *i += 1;
863	            0
864	        }
865	    }
866	}
867	
868	fn emit_le24(out: &mut Vec<u8>, val: u32) {
869	    out.push(val as u8);
870	    out.push((val >> 8) as u8);
871	    out.push((val >> 16) as u8);
872	}
873	
874	fn read_le24(bytes: &[u8]) -> u32 {
875	    u32::from(bytes[0]) | (u32::from(bytes[1]) << 8) | (u32::from(bytes[2]) << 16)
876	}
